import React, { useEffect, useRef } from "react";

export default function CallWindow({ currentUser, friend, callType, socket, onEnd }) {
  const localVideo = useRef(null);
  const remoteVideo = useRef(null);
  const peerConnection = useRef(null);

  useEffect(() => {
    peerConnection.current = new RTCPeerConnection();

    // Show remote stream
    peerConnection.current.ontrack = (event) => {
      if (remoteVideo.current) {
        remoteVideo.current.srcObject = event.streams[0];
      }
    };

    // Get local media based on callType
    const constraints = callType === "audio" ? { audio: true } : { video: true, audio: true };
    navigator.mediaDevices.getUserMedia(constraints).then((stream) => {
      if (localVideo.current && callType === "video") {
        localVideo.current.srcObject = stream; // show local video only for video calls
      }
      stream.getTracks().forEach(track => peerConnection.current.addTrack(track, stream));
    });

    // Handle ICE candidates
    peerConnection.current.onicecandidate = (event) => {
      if (event.candidate) {
        socket.emit("ice candidate", { toId: friend.userId, candidate: event.candidate });
      }
    };

    // Incoming call offer
    socket.on("incoming call", async ({ fromId, offer }) => {
      if (fromId === friend.userId) {
        await peerConnection.current.setRemoteDescription(new RTCSessionDescription(offer));
        const answer = await peerConnection.current.createAnswer();
        await peerConnection.current.setLocalDescription(answer);
        socket.emit("call answer", { fromId: currentUser.userId, toId: friend.userId, answer });
      }
    });

    // Call answered
    socket.on("call answered", async ({ fromId, answer }) => {
      if (fromId === friend.userId) {
        await peerConnection.current.setRemoteDescription(new RTCSessionDescription(answer));
      }
    });

    // ICE candidates
    socket.on("ice candidate", async (candidate) => {
      try {
        await peerConnection.current.addIceCandidate(new RTCIceCandidate(candidate));
      } catch (err) {
        console.error("Error adding ICE candidate", err);
      }
    });

    // Start call (send offer)
    const startCall = async () => {
      const offer = await peerConnection.current.createOffer();
      await peerConnection.current.setLocalDescription(offer);
      socket.emit("call request", {
        fromId: currentUser.userId,
        toId: friend.userId,
        callType,
        offer
      });
    };
    startCall();

    return () => {
      socket.off("incoming call");
      socket.off("call answered");
      socket.off("ice candidate");
      peerConnection.current.close();
    };
  }, [currentUser.userId, friend.userId, callType, socket]);

  return (
    <div style={styles.container}>
      <h2>{callType === "audio" ? "Audio Call" : "Video Call"} with {friend.userId}</h2>
      <div style={styles.videoBox}>
        {callType === "video" && <video ref={localVideo} autoPlay muted style={styles.video} />}
        <video ref={remoteVideo} autoPlay style={styles.video} />
      </div>
      <button style={styles.endBtn} onClick={onEnd}>End Call</button>
    </div>
  );
}

const styles = {
  container: {
    textAlign: "center",
    padding: 20,
    backgroundColor: "#ECE5DD",
    height: "100vh",
  },
  videoBox: {
    display: "flex",
    justifyContent: "center",
    gap: 10,
    marginBottom: 20,
  },
  video: {
    width: "45%",
    borderRadius: 10,
    border: "1px solid #ccc",
    backgroundColor: "black",
  },
  endBtn: {
    padding: "10px 20px",
    fontSize: 16,
    borderRadius: 20,
    border: "none",
    backgroundColor: "#d9534f",
    color: "white",
    cursor: "pointer",
  },
};
